def checkout_process(cart_items, user, discount_code_str, payment_info):
    # Step 1: Validate Cart Items
    if not cart_items:
        raise CheckoutError("Cart is empty.")
    for item in cart_items:
        if not isinstance(item, CartItem) or item.price <= 0 or item.quantity <= 0:
            raise CheckoutError(f"Invalid cart item: {item}")
    
    subtotal = sum(item.price * item.quantity for item in cart_items)
    
    checkout_data = {
        "cart_items": cart_items,
        "user": user,
        "subtotal": subtotal,
        "discount_applied": 0.0,
        "discount_code_used": None,
        "tax_amount": 0.0,
        "total_amount": subtotal,
        "payment_info": payment_info,
        "order_id": None
    }

    # Step 2: Apply Discount Codes
    if discount_code_str:
        available_discounts = {
            "SAVE10": DiscountCode("SAVE10", 0.10, min_amount=50),
            "PREMIUM20": DiscountCode("PREMIUM20", 0.20, allowed_tiers=['premium'], min_amount=100),
            "ADMIN50": DiscountCode("ADMIN50", 0.50, admin_only=True, min_amount=200),
            "VIP15": DiscountCode("VIP15", 0.15, allowed_tiers=['vip'])
        }
        
        discount_code = available_discounts.get(discount_code_str)
        if not discount_code:
            raise CheckoutError(f"Invalid discount code: {discount_code_str}")

        # Validate user permissions for discount code
        if discount_code.admin_only and not user.is_admin:
            raise CheckoutError(f"Discount code '{discount_code_str}' is for admins only.")
        
        if discount_code.allowed_tiers and user.user_tier not in discount_code.allowed_tiers and not user.is_admin:
            raise CheckoutError(f"Discount code '{discount_code_str}' is not allowed for your user tier.")

        if checkout_data["subtotal"] < discount_code.min_amount:
            raise CheckoutError(f"Discount code '{discount_code_str}' requires a minimum purchase of ${discount_code.min_amount:.2f}.")

        discount_amount = checkout_data["subtotal"] * discount_code.percentage
        checkout_data["discount_applied"] = discount_amount
        checkout_data["discount_code_used"] = discount_code_str
        checkout_data["total_amount"] -= discount_amount
        if checkout_data["total_amount"] < 0:
            checkout_data["total_amount"] = 0 # Ensure total doesn't go negative

    # Step 3: Calculate Tax
    TAX_RATE = 0.08 # Example tax rate (8%)
    tax_amount = checkout_data["total_amount"] * TAX_RATE
    checkout_data["tax_amount"] = tax_amount
    checkout_data["total_amount"] += tax_amount

    # Step 4: Process Payment
    # This is a mock payment processing step. In a real application, this would
    # involve calling a payment gateway API.
    if not isinstance(payment_info, PaymentInfo):
        raise CheckoutError("Invalid payment information provided.")
    
    if checkout_data["total_amount"] <= 0:
        # If total is 0 or less after discounts/taxes, no payment needed
        payment_status = "SKIPPED_ZERO_AMOUNT"
    else:
        # Simulate payment success/failure
        if payment_info.card_number.startswith("4") and len(payment_info.card_number) == 16: # Simple mock validation for Visa
            payment_status = "SUCCESS"
            # In a real system, you'd get a transaction ID here
            checkout_data["transaction_id"] = f"TXN-{uuid.uuid4()}"
        else:
            raise CheckoutError("Payment processing failed: Invalid card details or payment gateway error.")
    
    checkout_data["payment_status"] = payment_status

    # Step 5: Create Order Record
    order_id = str(uuid.uuid4())
    checkout_data["order_id"] = order_id
    
    # In a real system, this would involve saving the order to a database
